import math

def aliquot_sum(n):
    if n <= 1: return 0
    total = 1
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            total += i
            if i != n // i:
                total += n // i
    return total

if __name__ == "__main__":
    print(f"Aliquot sum of 12: {aliquot_sum(12)}")
